#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

bool l[N],r[N];

int main(){
    int t,n,ans,cnt;
    string s;
    scanf("%d",&t);
    while(t--){
        ans=cnt=0;
        scanf("%d",&n);
        cin>>s;
        s=" "+s;
        for(int i=2;i<=n;i++)
            l[i]=(s[i-1]=='B' && s[i]=='T' || l[i-2] && s[i-1]=='T' && s[i]=='B');
        r[n+1]=r[n]=false;
        for(int i=n-1;i;i--)
            r[i]=(s[i]=='T' && s[i+1]=='B' || r[i+2] && s[i]=='B' && s[i+1]=='T');
        for(int i=1;i<=n;i++){
            if(s[i]=='T')
                cnt++;
            else
                cnt=l[i];
            ans=max(ans,cnt+r[i+1]);
        }
        printf("%d\n",ans);
    }
    return 0;
}
